# ── SVG library ─────────────────────────────────────────────────────────────
def svg(path, w=20, h=20, sw="1.75"):
    return (f'<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" '
            f'stroke-width="{sw}" stroke="currentColor" '
            f'style="width:{w}px;height:{h}px;display:inline-block;vertical-align:middle">'
            f'{path}</svg>')

P = '<path stroke-linecap="round" stroke-linejoin="round" d="{d}"/>'
def p(d): return P.format(d=d)

