HTML_FILES = [
    'index.html', 'ai-index.html', 'kw-portfolio.html', 'travel.html',
    'projects.html', 'portfolio.html', 'setup-guide.html', 'privacy.html',
    'lucky7-predictions.html', 'lucky7-strikes.html',
]

total = 0
for fname in HTML_FILES:
    fpath = os.path.join(ROOT, fname)
    if not os.path.exists(fpath):
        continue
    text = open(fpath, encoding='utf-8').read()
    original = text
    for old, new in REPLACEMENTS:
        text = text.replace(old, new)
    changed = text.count('\n') != original.count('\n') or text != original
    if changed:
        with open(fpath, 'w', encoding='utf-8') as f:
            f.write(text)
        n = sum(1 for o, n2 in REPLACEMENTS if o in original)
        total += n
        print(f'  ✔ {fname} ({n} replacements)')
    else:
        print(f'  – {fname} (no changes)')

print(f'\nDone. ~{total} icon replacements applied.')
